/* Helpers */
static inline WamValue val_atom(const char *s) {
    // We avoid strdup here to prevent leaks, assuming 's' is a string literal.
    // Dynamic atoms will require an interning table later.
    WamValue v; v.tag = VAL_ATOM; v.data.atom = s; return v;
}
static inline WamValue val_int(int n) {
    WamValue v; v.tag = VAL_INT; v.data.integer = n; return v;
}
static inline WamValue val_float(double n) {
    WamValue v; v.tag = VAL_FLOAT; v.data.floating = n; return v;
}
static inline WamValue val_number_from_double(double n) {
    if (n >= (double)INT_MIN && n <= (double)INT_MAX && n == (double)((int)n)) {
        return val_int((int)n);
    }
    return val_float(n);
}
static inline WamValue val_unbound(const char *name) {
    WamValue v; v.tag = VAL_UNBOUND; v.data.unbound_name = name; return v;
}

static inline unsigned int wam_hash_string(const char *name) {
    unsigned int h = 5381;
    while (*name) h = ((h << 5) + h) ^ (unsigned char)*name++;
    return h;
}

static inline unsigned int wam_pred_hash(const char *name) {
    return wam_hash_string(name) & (WAM_PRED_HASH_SIZE - 1);
}

static inline void wam_register_predicate_hash(WamState *state,
                                                const char *name, int pc) {
    unsigned int idx = wam_pred_hash(name);
    unsigned int probes = 0;
    while (state->pred_hash[idx].name != NULL &&
           strcmp(state->pred_hash[idx].name, name) != 0 &&
           probes < WAM_PRED_HASH_SIZE) {
        idx = (idx + 1) & (WAM_PRED_HASH_SIZE - 1);
        probes++;
    }
    if (probes == WAM_PRED_HASH_SIZE) return;
    state->pred_hash[idx].name = name;
    state->pred_hash[idx].pc = pc;
}

static inline int resolve_predicate_hash(WamState *state, const char *name) {
    unsigned int idx = wam_pred_hash(name);
    unsigned int probes = 0;
    while (state->pred_hash[idx].name != NULL && probes < WAM_PRED_HASH_SIZE) {
        if (strcmp(state->pred_hash[idx].name, name) == 0)
            return state->pred_hash[idx].pc;
        idx = (idx + 1) & (WAM_PRED_HASH_SIZE - 1);
        probes++;
    }
    return -1;
}

static inline void wam_register_predicate(WamState *state, const char *pred, int pc) {
    wam_register_predicate_hash(state, pred, pc);
}

static inline int resolve_predicate(WamState *state, const char *pred) {
    return resolve_predicate_hash(state, pred);
}

static inline unsigned int wam_foreign_hash(const char *name, int arity) {
    unsigned int h = wam_hash_string(name);
    h = ((h << 5) + h) ^ (unsigned int)arity;
    return h & (WAM_FOREIGN_HASH_SIZE - 1);
}

static inline void wam_register_foreign_predicate(WamState *state,
                                                  const char *name,
                                                  int arity,
                                                  WamForeignHandler handler) {
    unsigned int idx = wam_foreign_hash(name, arity);
    unsigned int probes = 0;
    while (state->foreign_hash[idx].name != NULL &&
           (strcmp(state->foreign_hash[idx].name, name) != 0 ||
            state->foreign_hash[idx].arity != arity) &&
           probes < WAM_FOREIGN_HASH_SIZE) {
        idx = (idx + 1) & (WAM_FOREIGN_HASH_SIZE - 1);
        probes++;
    }
    if (probes == WAM_FOREIGN_HASH_SIZE) return;
    state->foreign_hash[idx].name = name;
    state->foreign_hash[idx].arity = arity;
    state->foreign_hash[idx].handler = handler;
}

static inline WamForeignHandler resolve_foreign_predicate(WamState *state,
                                                          const char *name,
                                                          int arity) {
    unsigned int idx = wam_foreign_hash(name, arity);
    unsigned int probes = 0;
    while (state->foreign_hash[idx].name != NULL && probes < WAM_FOREIGN_HASH_SIZE) {
        if (strcmp(state->foreign_hash[idx].name, name) == 0 &&
            state->foreign_hash[idx].arity == arity)
            return state->foreign_hash[idx].handler;
        idx = (idx + 1) & (WAM_FOREIGN_HASH_SIZE - 1);
        probes++;
    }
    return NULL;
}

static inline char *wam_strdup(const char *str) {
    size_t len = strlen(str) + 1;
    char *copy = malloc(len);
    if (copy) memcpy(copy, str, len);
    return copy;
}

static inline bool wam_atom_table_ensure(WamState *state) {
    if (state->atom_table) return true;
    state->atom_table_size = WAM_INITIAL_ATOM_HASH_SIZE;
    state->atom_table = calloc((size_t)state->atom_table_size, sizeof(AtomEntry *));
    if (!state->atom_table) {
        state->atom_table_size = 0;
        return false;
    }
    return true;
}

static inline bool wam_atom_table_rehash(WamState *state, int new_size) {
    AtomEntry **new_table = calloc((size_t)new_size, sizeof(AtomEntry *));
    if (!new_table) return false;
    for (int i = 0; i < state->atom_table_size; i++) {
        AtomEntry *entry = state->atom_table[i];
        while (entry) {
            AtomEntry *next = entry->next;
            unsigned int h = wam_hash_string(entry->str) & (unsigned int)(new_size - 1);
            entry->next = new_table[h];
            new_table[h] = entry;
            entry = next;
        }
    }
    free(state->atom_table);
    state->atom_table = new_table;
    state->atom_table_size = new_size;
    return true;
}

static inline const char *wam_intern_atom(WamState *state, const char *str) {
    if (!wam_atom_table_ensure(state)) return str;
    unsigned int h = wam_hash_string(str) & (unsigned int)(state->atom_table_size - 1);
    for (AtomEntry *e = state->atom_table[h]; e; e = e->next) {
        if (strcmp(e->str, str) == 0) return e->str;
    }
    if ((state->atom_count + 1) * 4 > state->atom_table_size * 3 &&
        state->atom_table_size <= INT_MAX / 2 &&
        wam_atom_table_rehash(state, state->atom_table_size * 2)) {
        h = wam_hash_string(str) & (unsigned int)(state->atom_table_size - 1);
    }
    AtomEntry *e = malloc(sizeof(AtomEntry));
    if (!e) return str;
    e->str = wam_strdup(str);
    if (!e->str) {
        free(e);
        return str;
    }
    e->next = state->atom_table[h];
    state->atom_table[h] = e;
    state->atom_count++;
    return e->str;
}
// Creates a new unbound reference on the heap.
// Note: This function allocates a cell in H_array and increments state->H.
// This fulfills the 1-slot allocation invariant expected by UNIFY_* write-mode operations.
static inline WamValue wam_make_ref(WamState *state) {
    if (state->H >= state->H_cap) {
        state->H_cap = state->H_cap ? state->H_cap * 2 : WAM_INITIAL_CAP;
        state->H_array = realloc(state->H_array, sizeof(WamValue) * state->H_cap);
    }
    WamValue ref;
    ref.tag = VAL_REF;
    ref.data.ref_addr = state->H;
    state->H_array[state->H] = val_unbound("heap_var");
    state->H++;
    return ref;
}
static inline bool val_is_unbound(WamValue v) {
    return v.tag == VAL_UNBOUND;
}
static inline bool val_equal(WamValue v1, WamValue v2) {
    if (v1.tag != v2.tag) return false;
    if (v1.tag == VAL_INT) return v1.data.integer == v2.data.integer;
    if (v1.tag == VAL_FLOAT) return v1.data.floating == v2.data.floating;
    if (v1.tag == VAL_ATOM) return strcmp(v1.data.atom, v2.data.atom) == 0;
    // simplify for demonstration
    return false;
}
static inline WamValue* resolve_reg(WamState *state, int reg_idx, int is_y) {
    if (is_y == 1) {
        assert(state->E >= 0 && "Y-register accessed with empty environment stack");
        return &state->E_array[state->E].y_regs[reg_idx];
    }
    if (is_y == 2) {
        return &state->X[reg_idx];
    }
    return &state->A[reg_idx];
}
static inline void trail_binding(WamState *state, WamValue *cell) {
    if (state->TR >= state->TR_cap) {
        state->TR_cap = state->TR_cap ? state->TR_cap * 2 : WAM_INITIAL_CAP;
        state->TR_array = realloc(state->TR_array, sizeof(TrailEntry) * state->TR_cap);
    }
    state->TR_array[state->TR].cell = cell;
    state->TR_array[state->TR].old_val = *cell;
    state->TR++;
}
static inline WamValue* wam_deref_ptr(WamState *state, WamValue *v) {
    while (v->tag == VAL_REF) {
        WamValue *next = &state->H_array[v->data.ref_addr];
        if (next->tag == VAL_UNBOUND) return next;
        if (next->tag == VAL_REF && next->data.ref_addr == v->data.ref_addr) break;
        v = next;
    }
    return v;
}
static inline void wam_bind(WamState *state, WamValue *v1, WamValue *v2) {
    trail_binding(state, v1);
    *v1 = *v2;
}
/* Return the heap address of a cons cell's head, treating both a VAL_LIST
   (head@addr, tail@addr+1) and a "[|]/2"/"./2" VAL_STR (functor@addr,
   head@addr+1, tail@addr+2) as the same list cell; -1 if not a cons. The
   compiler mixes the two spellings for one logical list (put_list vs
   put_structure "[|]/2"), so unification must alias them. */
static inline int wam_cons_head_addr(WamState *state, WamValue *d) {
    if (d->tag == VAL_LIST) return d->data.ref_addr;
    if (d->tag == VAL_STR) {
        WamValue *f = &state->H_array[d->data.ref_addr];
        if (f->tag == VAL_ATOM &&
            (strcmp(f->data.atom, "[|]/2") == 0 || strcmp(f->data.atom, "./2") == 0)) {
            return d->data.ref_addr + 1;
        }
    }
    return -1;
}
static inline bool wam_unify(WamState *state, WamValue *v1, WamValue *v2) {
    WamValue *pdl[256];
    int pdl_top = 0;
    
    pdl[pdl_top++] = v2;
    pdl[pdl_top++] = v1;
    
    while (pdl_top > 0) {
        WamValue *d1 = wam_deref_ptr(state, pdl[--pdl_top]);
        WamValue *d2 = wam_deref_ptr(state, pdl[--pdl_top]);
        
        if (d1 == d2) continue;
        
        if (d1->tag == VAL_UNBOUND || d2->tag == VAL_UNBOUND) {
            WamValue *unbound = (d1->tag == VAL_UNBOUND) ? d1 : d2;
            WamValue *other = (d1->tag == VAL_UNBOUND) ? d2 : d1;
            wam_bind(state, unbound, other);
            continue;
        }

        /* Cons-cell aliasing: a VAL_LIST and a "[|]/2"/"./2" VAL_STR are the
           same list cell. Unify head with head and tail with tail. */
        {
            int c1 = wam_cons_head_addr(state, d1);
            int c2 = wam_cons_head_addr(state, d2);
            if (c1 >= 0 && c2 >= 0) {
                if (pdl_top + 4 > 256) return false;
                pdl[pdl_top++] = &state->H_array[c2 + 1];
                pdl[pdl_top++] = &state->H_array[c1 + 1];
                pdl[pdl_top++] = &state->H_array[c2];
                pdl[pdl_top++] = &state->H_array[c1];
                continue;
            }
        }

        if (d1->tag != d2->tag) return false;
        
        if (d1->tag == VAL_INT) {
            if (d1->data.integer != d2->data.integer) return false;
        } else if (d1->tag == VAL_FLOAT) {
            if (d1->data.floating != d2->data.floating) return false;
        } else if (d1->tag == VAL_ATOM) {
            if (strcmp(d1->data.atom, d2->data.atom) != 0) return false;
        } else if (d1->tag == VAL_LIST) {
            if (pdl_top + 4 > 256) return false; // PDL overflow
            // Push tail first, then head, so head is popped and unified first
            pdl[pdl_top++] = &state->H_array[d2->data.ref_addr + 1];
            pdl[pdl_top++] = &state->H_array[d1->data.ref_addr + 1];
            pdl[pdl_top++] = &state->H_array[d2->data.ref_addr];
            pdl[pdl_top++] = &state->H_array[d1->data.ref_addr];
        } else if (d1->tag == VAL_STR) {
            WamValue *f1 = &state->H_array[d1->data.ref_addr];
            WamValue *f2 = &state->H_array[d2->data.ref_addr];
            if (f1->tag != VAL_ATOM || f2->tag != VAL_ATOM) return false;
            if (strcmp(f1->data.atom, f2->data.atom) != 0) return false;
            
            const char *slash = strchr(f1->data.atom, '/');
            assert(slash != NULL && "Functor missing arity suffix");
            int arity = strtol(slash + 1, NULL, 10);
            
            if (pdl_top + arity * 2 > 256) return false; // PDL overflow
            // Push right-to-left so arguments are popped and unified left-to-right
            for (int i = arity - 1; i >= 0; i--) {
                pdl[pdl_top++] = &state->H_array[d2->data.ref_addr + 1 + i];
                pdl[pdl_top++] = &state->H_array[d1->data.ref_addr + 1 + i];
            }
        } else {
            return false;
        }
    }
    return true;
}
static inline void push_choice_point(WamState *state, int next_pc, int arity) {
    if (state->B >= state->B_cap) {
        state->B_cap = state->B_cap ? state->B_cap * 2 : WAM_INITIAL_CAP;
        state->B_array = realloc(state->B_array, sizeof(ChoicePoint) * state->B_cap);
    }
    ChoicePoint *cp = &state->B_array[state->B];
    cp->next_pc = next_pc;
    cp->cp = state->CP;
    cp->heap_size = state->H;
    cp->trail_size = state->TR;
    cp->stack_size = state->E;
    cp->call_base_top = state->call_base_top;
    
    int save_arity = arity < 32 ? arity : 32;
    cp->arity = save_arity;
    memcpy(cp->a_regs, state->A, sizeof(WamValue) * save_arity);
    state->B++;
    state->HB = state->H;
}
static inline void unwind_trail(WamState *state, int target_tr) {
    while (state->TR > target_tr) {
        state->TR--;
        TrailEntry *te = &state->TR_array[state->TR];
        *te->cell = te->old_val;
    }
}
static inline void restore_choice_point(WamState *state, ChoicePoint *cp) {
    state->H = cp->heap_size;
    state->E = cp->stack_size;
    state->CP = cp->cp;
    state->call_base_top = cp->call_base_top;
    unwind_trail(state, cp->trail_size);
    memcpy(state->A, cp->a_regs, sizeof(WamValue) * cp->arity);
}
static inline void pop_choice_point(WamState *state) {
    if (state->B > 0) {
        state->B--;
        if (state->B > 0) {
            state->HB = state->B_array[state->B - 1].heap_size;
        } else {
            state->HB = 0;
        }
    }
}
static inline void wam_prune_choice_points(WamState *state, int target_b) {
    while (state->B > target_b) {
        pop_choice_point(state);
    }
}
static inline void update_choice_point(WamState *state, int next_pc) {
    if (state->B > 0) {
        state->B_array[state->B - 1].next_pc = next_pc;
    }
}

#endif /* WAM_RUNTIME_H */
